# Initialize workbook and worksheet
wb = Workbook()
ws = wb.active
ws.title = "Generated Layout"

# Constants for grid and offsets
col_offset = 1
row_padding = 2
default_font_size = 9
max_col_index = 36
max_row_base = 50

# Apply grid settings (column widths and row heights)
for c in range(1, max_col_index + 1):
    ws.column_dimensions[get_column_letter(c)].width = 2.53
for r in range(1, (len(data) * max_row_base) + max_row_base): # Extend row heights for potential future pages
    ws.row_dimensions[r].height = 17.01

# Define border style
thin = Side(style='thin')

# Function to apply borders
def apply_border(ws, s_row, e_row, s_col, e_col, borders):
    has_top = borders.get("top", True)
    has_bottom = borders.get("bottom", True)
    has_left = borders.get("left", True)
    has_right = borders.get("right", True)
    for r in range(s_row, e_row + 1):
        for c in range(s_col, e_col + 1):
            target = ws.cell(row=r, column=c)
            try:
                target.alignment = Alignment(horizontal='left', vertical='center', wrap_text=False)
            except AttributeError:
                pass
            top = thin if (r == s_row and has_top) else None
            bottom = thin if (r == e_row and has_bottom) else None
            left = thin if (c == s_col and has_left) else None
            right = thin if (c == e_col and has_right) else None
            try:
                target.border = Border(top=top, bottom=bottom, left=left, right=right)
            except AttributeError:
                pass

# Process elements from the input data
max_used_row = 0
for page in data:
    page_number = page["page_number"]
    current_row_offset = (page_number - 1) * (max_row_base + row_padding)
    
    for item in page["elements"]:
        if item["type"] == "text":
            r = item["row"] + current_row_offset
            
            # Clamp coordinates
            r = min(r, 50)
            item["col"] = min(item["col"], 36)
            if "end_col" in item:
                item["end_col"] = min(item["end_col"], 36)

            # Update max_used_row
            max_used_row = max(max_used_row, r)
            if "end_row" in item:
                 max_used_row = max(max_used_row, item["end_row"] + current_row_offset)

            cell = ws.cell(row=r, column=item["col"])
            cell.value = item["content"]
            
            if item.get("is_vertical"):
                cell.alignment = Alignment(text_rotation=255, vertical='top', wrap_text=False)
            else:
                cell.alignment = Alignment(horizontal='left', vertical='center', wrap_text=False)
                
            font_kwargs = {"size": item.get("font_size") or default_font_size}
            if item.get("font_color"):
                font_kwargs["color"] = item["font_color"]
            cell.font = Font(**font_kwargs)

        elif item["type"] == "border_rect":
            s_row = item["row"] + current_row_offset
            e_row = item["end_row"] + current_row_offset
            s_col = item["col"]
            e_col = item["end_col"]

            # Clamp coordinates
            s_row = min(s_row, 50)
            e_row = min(e_row, 50)
            s_col = min(s_col, 36)
            e_col = min(e_col, 36)
            
            # Update max_used_row
            max_used_row = max(max_used_row, e_row)

            apply_border(
                ws,
                s_row, e_row,
                s_col, e_col,
                item.get("borders", {"top": True, "bottom": True, "left": True, "right": True})
            )

    # Add page break after each page's content, except the last one
    if page_number < len(data):
        ws.row_breaks.append(Break(id= (page_number) * (max_row_base + row_padding)))

# Set print range
# Calculate the actual maximum used row and column across all pages
actual_max_row = 0
actual_max_col = 0
for page in data:
    for item in page["elements"]:
        actual_max_row = max(actual_max_row, item["row"])
        actual_max_col = max(actual_max_col, item["col"])
        if "end_row" in item:
            actual_max_row = max(actual_max_row, item["end_row"])
        if "end_col" in item:
            actual_max_col = max(actual_max_col, item["end_col"])

# Apply print range based on actual used rows and columns + 1 for header row/col and 1 for inclusivity
print_range_end_col_letter = get_column_letter(min(actual_max_col + 1, 36)) # Clamp to max column
print_range_end_row = min(actual_max_row + 1, 50) # Clamp to max row

ws.print_area = f"A1:{print_range_end_col_letter}{print_range_end_row}"

# Set page setup and margins
ws.page_setup.paperSize = 9
ws.page_setup.orientation = 'portrait'

# Correctly set page margins using attribute assignment
ws.page_margins.left = 0.47
ws.page_margins.right = 0.47
ws.page_margins.top = 0.41
ws.page_margins.bottom = 0.41
ws.page_margins.header = 0.0 # Added default values for header/footer as they might be expected
ws.page_margins.footer = 0.0

# Save the workbook
wb.save("output.xlsx")